Future&lt;bool&gt; ajouterAuPanier(int productId, int quantite) async {
  final url = Uri.parse('https://api.ma-boutique.com/panier/ajouter');
  final body = jsonEncode({'productId': productId, 'quantite': quantite});

  try {
    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: body,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      // Succès
      print('Produit ajouté avec succès');
      return true;
    } else {
      // Erreur HTTP
      print('Erreur serveur : ${response.statusCode} - ${response.body}');
      return false;
    }
  } catch (e) {
    // Exception réseau ou autre
    print('Erreur réseau ou d'envoi : $e');
    return false;
  }
}
