import 'dart:convert';
import 'package:http/http.dart' as http;

class WeatherService {
  final String baseUrl = 'https://api.open-meteo.com/v1/forecast';

  Future&lt;double?&gt; getCurrentTemperature(double latitude, double longitude) async {
    final url = Uri.parse('$baseUrl?latitude=$latitude&longitude=$longitude&current_weather=true');

    try {
      final response = await http.get(url);
      if (response.statusCode == 200) {
        final Map&lt;String, dynamic&gt; data = jsonDecode(response.body);
        if (data.containsKey('current_weather') && data['current_weather'] != null) {
          final currentWeather = data['current_weather'] as Map&lt;String, dynamic&gt;;
          if (currentWeather.containsKey('temperature')) {
            return currentWeather['temperature'] as double;
          }
        }
        return null; // Structure JSON inattendue
      } else {
        print('Erreur HTTP : ${response.statusCode}');
        return null;
      }
    } catch (e) {
      print('Exception lors de l'appel API : $e');
      return null;
    }
  }
}
